     1|/**
     2| * IVX Secure Variable Vault — independence layer for credentials.
     3| *
     4| * All IVX-owned credentials use the IVX_ prefix to distinguish them from
     5| * Rork-provided env vars. Every credential is tested before use. Missing
     6| * credentials return the exact variable name. Invalid credentials return
     7| * the exact HTTP error. No secret value is ever printed or logged.
     8| *
     9| * Vault variables:
    10| *   IVX_GITHUB_TOKEN       — GitHub personal access token
    11| *   IVX_RENDER_API_KEY     — Render API key
    12| *   IVX_RENDER_SERVICE_ID  — Render service ID
    13| *   IVX_SUPABASE_URL       — Supabase project URL
    14| *   IVX_SUPABASE_SERVICE_ROLE_KEY — Supabase service role key
    15| *   IVX_AWS_ACCESS_KEY_ID  — AWS access key
    16| *   IVX_AWS_SECRET_ACCESS_KEY — AWS secret key
    17| *   IVX_VERCEL_TOKEN       — Vercel API token
    18| *   IVX_OWNER_TOKEN        — Owner service token
    19| *
    20| * Fallback: when IVX_ prefixed vars are absent, the vault falls back to
    21| * the Rork-provided env vars (GITHUB_TOKEN, RENDER_API_KEY, etc.) so the
    22| * system degrades gracefully rather than breaking.
    23| */
    24|
    25|const VAULT_MARKER = 'ivx-secure-vault-2026-07-02';
    26|
    27|// ─── Vault Entry Definitions ────────────────────────────────────────
    28|
    29|export type VaultCategory = 'github' | 'render' | 'supabase' | 'aws' | 'vercel' | 'google_play' | 'apple_store' | 'auth' | 'other';
    30|
    31|export type VaultEntry = {
    32|  /** IVX-prefixed variable name (e.g. IVX_GITHUB_TOKEN) */
    33|  ivxName: string;
    34|  /** Rork-provided fallback name (e.g. GITHUB_TOKEN) */
    35|  fallbackName: string | null;
    36|  category: VaultCategory;
    37|  required: boolean;
    38|  purpose: string;
    39|  /** Live test function — returns ok/fail with detail, never the value */
    40|  test: (value: string) => Promise<{ ok: boolean; detail: string }>;
    41|};
    42|
    43|export type VaultVariableStatus = {
    44|  name: string;
    45|  category: VaultCategory;
    46|  required: boolean;
    47|  purpose: string;
    48|  /** true when at least one source provides a non-empty value */
    49|  present: boolean;
    50|  /** ivx, fallback, or none */
    51|  source: 'ivx' | 'fallback' | 'none';
    52|  /** source variable name that provided the value */
    53|  sourceVar: string | null;
    54|  /** length of the value (never the value itself) */
    55|  valueLength: number;
    56|  /** tested against the live API */
    57|  tested: boolean;
    58|  /** result of the live test */
    59|  testOk: boolean | null;
    60|  /** detail from the test (HTTP status, error message) */
    61|  testDetail: string | null;
    62|  /** secret values are never returned — always false */
    63|  secretValuesReturned: false;
    64|};
    65|
    66|export type VaultAudit = {
    67|  marker: string;
    68|  generatedAt: string;
    69|  total: number;
    70|  present: number;
    71|  missing: number;
    72|  tested: number;
    73|  passed: number;
    74|  failed: number;
    75|  variables: VaultVariableStatus[];
    76|  requiredPresent: boolean;
    77|  requiredMissing: string[];
    78|  blockers: string[];
    79|  secretValuesReturned: false;
    80|};
