   114|async function testGitHubToken(token: string): Promise<{ ok: boolean; detail: string }> {
   115|  try {
   116|    const res = await fetch('https://api.github.com/user', {
   117|      headers: {
   118|        Authorization: `Bearer ${token}`,
   119|        Accept: 'application/vnd.github+json',
   120|        'X-GitHub-Api-Version': '2022-11-28',
   121|      },
   122|      signal: AbortSignal.timeout(10000),
   123|    });
