   125|      const data = await res.json().catch(() => null) as { login?: string; scopes?: string } | null;
   126|      const login = data?.login ?? 'unknown';
   127|      return { ok: true, detail: `authenticated as ${login}` };
   128|    }
   129|    if (res.status === 401) return { ok: false, detail: 'HTTP 401 — token invalid or expired' };
   130|    if (res.status === 403) return { ok: false, detail: 'HTTP 403 — insufficient permissions or rate limited' };
   131|    return { ok: false, detail: `HTTP ${res.status}` };
   132|  } catch (err) {
