   350|/**
   351| * Inspect a single vault variable: presence, source, length, and live test.
   352| * NEVER returns the secret value.
   353| */
   354|export async function inspectVaultVariable(ivxName: string): Promise<VaultVariableStatus | null> {
   355|  const entry = VAULT_REGISTRY.find((e) => e.ivxName === ivxName);
   356|  if (!entry) return null;
   357|
   358|  const { present, source, sourceVar, value } = readVault(entry.ivxName, entry.fallbackName);
   359|
   360|  let tested = false;
   361|  let testOk: boolean | null = null;
   362|  let testDetail: string | null = null;
   363|
   364|  if (present) {
   365|    try {
   366|      const result = await entry.test(value);
   367|      tested = true;
   368|      testOk = result.ok;
   369|      testDetail = result.detail;
   370|    } catch (err) {
   371|      tested = true;
   372|      testOk = false;
   373|      testDetail = `test threw: ${err instanceof Error ? err.message : String(err)}`;
   374|    }
   375|  }
   376|
   377|  return {
   378|    name: entry.ivxName,
   379|    category: entry.category,
   380|    required: entry.required,
   381|    purpose: entry.purpose,
   382|    present,
   383|    source,
   384|    sourceVar,
   385|    valueLength: value.length,
   386|    tested,
   387|    testOk,
   388|    testDetail,
   389|    secretValuesReturned: false,
   390|  };
   391|}
