   393|/**
   394| * Run a full vault audit: inspect every variable, run live tests, and
   395| * produce a blocking/missing report. Never returns secret values.
   396| */
   397|export async function auditVault(): Promise<VaultAudit> {
   398|  const variables: VaultVariableStatus[] = [];
   399|  const blockers: string[] = [];
   400|  const requiredMissing: string[] = [];
   401|
   402|  // Inspect all vault variables in parallel (with a concurrency cap of 5)
   403|  const chunks: VaultEntry[][] = [];
   404|  for (let i = 0; i < VAULT_REGISTRY.length; i += 5) {
   405|    chunks.push(VAULT_REGISTRY.slice(i, i + 5));
   406|  }
   407|
   408|  for (const chunk of chunks) {
   409|    const results = await Promise.all(
   410|      chunk.map((entry) => inspectVaultVariable(entry.ivxName)),
   411|    );
   412|    for (const result of results) {
   413|      if (result) variables.push(result);
   414|    }
   415|  }
   416|
   417|  for (const v of variables) {
   418|    if (!v.present) {
   419|      if (v.required) {
   420|        requiredMissing.push(v.name);
   421|        blockers.push(`MISSING_REQUIRED: ${v.name} — ${v.purpose}. Set ${v.name} in Render env vars or .env.`);
   422|      }
   423|    } else if (v.tested && v.testOk === false) {
   424|      blockers.push(`INVALID: ${v.name} — test failed: ${v.testDetail}. Source: ${v.sourceVar}.`);
   425|    }
   426|  }
   427|
   428|  const present = variables.filter((v) => v.present).length;
   429|  const missing = variables.filter((v) => !v.present).length;
   430|  const tested = variables.filter((v) => v.tested).length;
   431|  const passed = variables.filter((v) => v.tested && v.testOk === true).length;
   432|  const failed = variables.filter((v) => v.tested && v.testOk === false).length;
   433|
   434|  return {
   435|    marker: VAULT_MARKER,
   436|    generatedAt: new Date().toISOString(),
   437|    total: variables.length,
   438|    present,
   439|    missing,
   440|    tested,
   441|    passed,
   442|    failed,
   443|    variables,
   444|    requiredPresent: requiredMissing.length === 0,
   445|    requiredMissing,
   446|    blockers,
   447|    secretValuesReturned: false,
   448|  };
   449|}
