   451|/**
   452| * Build a quick credential summary suitable for status endpoints.
   453| * No network calls — just checks presence.
   454| */
   455|export function buildVaultStatus(): {
   456|  ok: boolean;
   457|  credentials: Record<string, { present: boolean; source: string | null }>;
   458|  secretValuesReturned: false;
   459|} {
   460|  const credentials: Record<string, { present: boolean; source: string | null }> = {};
   461|  let allRequiredPresent = true;
   462|
   463|  for (const entry of VAULT_REGISTRY) {
   464|    const { present, sourceVar } = readVault(entry.ivxName, entry.fallbackName);
   465|    credentials[entry.ivxName] = { present, source: sourceVar };
   466|    if (entry.required && !present) allRequiredPresent = false;
   467|  }
   468|
   469|  return {
   470|    ok: allRequiredPresent,
   471|    credentials,
   472|    secretValuesReturned: false,
   473|  };
   474|}
   475|
   476|export { VAULT_MARKER, VAULT_REGISTRY };
   477|export default { auditVault, inspectVaultVariable, getVaultValue, buildVaultStatus, VAULT_REGISTRY, VAULT_MARKER };

