   123|/**
   124| * Fetch the GitHub commit SHA. Tries the GitHub API first with the token.
   125| * If the token is expired/invalid (401), falls back to the Render deploy API
   126| * which reports the commit SHA of the connected GitHub repo's latest deploy.
   127| */
   128|async function resolveGitHubSha(renderInfo?: RenderInfo): Promise<GitHubShaResult> {
   129|  const token = process.env.GITHUB_TOKEN?.trim();
   130|
   131|  if (token) {
   132|    try {
   133|      const res = await fetch(`https://api.github.com/repos/${GITHUB_REPO}/commits?per_page=1`, {
   134|        headers: { Authorization: `Bearer ${token}`, Accept: 'application/vnd.github+json' },
   135|        signal: AbortSignal.timeout(10000),
   136|      });
   137|      if (res.ok) {
   138|        const data = await res.json() as Array<{ sha: string }>;
   139|        if (data[0]?.sha) {
   140|          return { sha: data[0].sha, source: 'github_api', tokenStatus: 'VALID' };
   141|        }
   142|      }
   143|      if (res.status === 401) {
   144|        console.log('[DeploymentBrain] GitHub token returned 401 — falling back to Render deploy SHA');
   145|      } else {
   146|        console.log(`[DeploymentBrain] GitHub API returned HTTP ${res.status} — falling back to Render deploy SHA`);
   147|      }
   148|    } catch (err) {
   149|      console.log('[DeploymentBrain] GitHub API fetch failed — falling back to Render deploy SHA:', err instanceof Error ? err.message : 'unknown');
   150|    }
   151|  }
   152|
   153|  // Fallback: Render deploy API includes the commit SHA from the connected GitHub repo
   154|  const info = renderInfo ?? await fetchRenderInfo();
   155|  if (info.sha) {
   156|    return {
   157|      sha: info.sha,
   158|      source: 'render_deploy_commit',
   159|      tokenStatus: token ? 'EXPIRED_OR_INVALID' : 'NOT_SET',
   160|    };
   161|  }
   162|
   163|  return { sha: null, source: 'none', tokenStatus: token ? 'EXPIRED_OR_INVALID' : 'NOT_SET' };
   164|}
