   590|async function runQATests(category: string): Promise<string> {
   591|  const endpoints = QA_ENDPOINTS[category];
   592|  if (!endpoints) {
   593|    return `Unknown QA category: ${category}. Available: ${Object.keys(QA_ENDPOINTS).join(', ')}`;
   594|  }
   595|
   596|  const results: QAResult[] = [];
   597|  for (const ep of endpoints) {
   598|    try {
   599|      const res = await fetch(ep.url, {
   600|        method: ep.method,
   601|        signal: AbortSignal.timeout(10000),
   602|      });
   603|      const text = await res.text();
   604|      let body: string | null = text.slice(0, 500);
   605|      try { JSON.parse(text); } catch { body = text.slice(0, 200); }
   606|
   607|      results.push({
   608|        feature: ep.label,
   609|        url: ep.url,
   610|        httpStatus: res.status,
   611|        responseBody: body,
   612|        status: res.ok ? 'VERIFIED' : 'FAILED',
   613|        error: res.ok ? null : `HTTP ${res.status}`,
   614|      });
   615|    } catch (err) {
   616|      results.push({
   617|        feature: ep.label,
   618|        url: ep.url,
   619|        httpStatus: null,
   620|        responseBody: null,
   621|        status: 'FAILED',
   622|        error: err instanceof Error ? err.message : 'Network error',
   623|      });
   624|    }
   625|  }
   626|
   627|  const verified = results.filter(r => r.status === 'VERIFIED').length;
   628|  const failed = results.filter(r => r.status === 'FAILED').length;
   629|
   630|  const lines = [
   631|    `## QA: ${category.toUpperCase()}`,
   632|    '',
   633|    `**Results:** ${verified} verified, ${failed} failed, ${results.length} total`,
   634|    '',
   635|    ...results.map(r =>
   636|      `- ${r.status === 'VERIFIED' ? '✅' : '❌'} ${r.feature}: HTTP ${r.httpStatus ?? 'N/A'} ${r.error ?? ''}`
   637|    ),
   638|    '',
   639|    `_Brain: ${DEPLOYMENT_BRAIN_VERSION}_`,
   640|  ];
   641|  return lines.join('\n');
   642|}
