   982|/**
   983| * Route a chat message that starts with "/" to the deployment brain.
   984| * Returns the brain's answer string, or null if not a deployment command.
   985| */
   986|export async function routeDeploymentCommand(message: string): Promise<string | null> {
   987|  const trimmed = message.trim();
   988|  if (!trimmed.startsWith('/')) return null;
   989|
   990|  const command = trimmed.split(/\s+/)[0].toLowerCase();
   991|
   992|  const handler = COMMAND_MAP[command];
   993|  if (!handler) return null;
   994|
   995|  console.log('[DeploymentBrain] Command routed:', { command, timestamp: nowIso() });
   996|  try {
   997|    return await handler();
   998|  } catch (err) {
